public int[] withoutTen(int[] nums)
{
  	int[] result = new int[nums.length];
  	int count = 0;

    for (int i = 0; i < nums.length; i++)
    {
     	if (nums[i] != 10)
        {
         	result[count] = nums[i];
            count++;
        }
    }
    for (int i = 0; i < count; i++)
    {
     	result[result.length - i] = 0;
    }

    return result;
}

